```typescript
import { INestApplication } from '@nestjs/common';
import { APP_GUARD } from '@nestjs/core';
import { Test, TestingModule } from '@nestjs/testing';
import { ThrottlerGuard, ThrottlerModule } from '@nestjs/throttler';
import * as request from 'supertest';
import { App } from 'supertest/types';

import { HealthModule } from '@modules/health/health.module';

import { CorrelationIdMiddleware } from '@middlewares/correlation-id.middleware';

const TTL = 1000;
const LIMIT = 3;

describe('App module', () => {
	let app: INestApplication;
	let getHttpServer: App;

	beforeAll(async () => {
		const testingModule: TestingModule = await Test.createTestingModule({
			imports: [
				ThrottlerModule.forRoot({ throttlers: [{ ttl: TTL, limit: LIMIT }] }),
				HealthModule,
			],
			providers: [{ provide: APP_GUARD, useClass: ThrottlerGuard }],
		}).compile();

		app = testingModule.createNestApplication();
		const correlationIdMiddleware = new CorrelationIdMiddleware();
		app.use(correlationIdMiddleware.use.bind(correlationIdMiddleware));
		getHttpServer = app.getHttpServer() as App;
		await app.init();
	});

	beforeEach(async () => {
		await new Promise((resolve) => setTimeout(resolve, TTL + 500));
	});

	afterAll(async () => {
		await app.close();
	});

	describe('Rate Limiting (e2e)', () => {
		it('should allow requests within rate limit', async () => {
			for (let i = 0; i < LIMIT; i++) {
				const res = await request(getHttpServer).get('/is_it_up');
				expect(res.status).toBe(200);
				expect((res.body as { status: string }).status).toBe('up');
			}
		});

		it('should block requests exceeding rate limit', async () => {
			for (let i = 0; i < LIMIT; i++) {
				const res = await request(getHttpServer).get('/is_it_up');
				expect(res.status).toBe(200);
			}

			const limitedRes = await request(getHttpServer).get('/is_it_up');
			expect(limitedRes.status).toBe(429);
		});

		it('should allow requests again after TTL expires', async () => {
			for (let i = 0; i < LIMIT; i++) {
				const res = await request(getHttpServer).get('/is_it_up');
				expect(res.status).toBe(200);
			}

			const limitedRes = await request(getHttpServer).get('/is_it_up');
			expect(limitedRes.status).toBe(429);

			await new Promise((resolve) => setTimeout(resolve, TTL + 200));

			const newRes = await request(getHttpServer).get('/is_it_up');
			expect(newRes.status).toBe(200);
		}, 15000);
	});
});
