export async function createMockStyleInDB(
	knex: Knex,
	styleData: Partial<IStyleBase> = {},
): Promise<void> {
	const uniqueId = styleData._id ?? `style_${styleData.style_id ?? Date.now()}`;
	const mockStyle = createMockStyle({ ...styleData, _id: uniqueId });

	const existing = await knex(TABLE_NAME_STYLES)
		.where({ style_id: mockStyle.style_id })
		.first();

	if (!existing) {
		await knex(TABLE_NAME_STYLES).insert({
			...mockStyle,
			categories_ids: JSON.stringify(mockStyle.categories_ids),
			categories_with_parents_ids: JSON.stringify(mockStyle.categories_with_parents_ids),
			sizes: JSON.stringify(mockStyle.sizes),
			broad_category_names: JSON.stringify(mockStyle.broad_category_names),
			sub_category_names: JSON.stringify(mockStyle.sub_category_names),
			brand: JSON.stringify(mockStyle.brand),
		});
	}
}
